/**
 * ScratchPlayer — открывает .sb3 проект в forkphorus-плеере (Scratch-совместимый)
 * только для просмотра/игры.
 * /scratch/play/:id          — авторизованный просмотр своего/ученического
 * /scratch/share/:token      — публичный по токену
 */

import { useEffect, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { BASE } from '../api/client'
import { getAccessToken } from '../lib/authStorage'
import { getScratchProject, fetchPublicScratch, toggleSharePublic, type ScratchProjectDto } from '../api/scratchProjects'

export default function ScratchPlayer({ publicMode = false }: { publicMode?: boolean }) {
  const navigate = useNavigate()
  const { id, token } = useParams<{ id?: string; token?: string }>()
  const { toast, show } = useToast()

  const [project, setProject] = useState<ScratchProjectDto | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    setLoading(true)
    const promise: Promise<ScratchProjectDto> = publicMode && token
      ? fetchPublicScratch(token)
      : id
        ? getScratchProject(id).then((r) => r.project)
        : Promise.reject(new Error('Не указан проект'))

    promise.then(setProject).catch(() => show('Не удалось загрузить', 'error')).finally(() => setLoading(false))
  }, [id, token, publicMode])

  const fileUrl = !project ? null
    : publicMode && token
      ? `${BASE}/scratch-projects/public/${token}/file`
      : `${BASE}/scratch-projects/${project.id}/file?token=${getAccessToken() ?? ''}`

  // forkphorus.github.io умеет встраивать произвольный .sb3 по URL.
  // Настоящий Scratch player (scratch.mit.edu/projects/{id}/embed) требует
  // числовой Scratch ID и работает только с проектами, загруженными на
  // scratch.mit.edu — для наших .sb3 файлов он не подходит.
  const playerUrl = fileUrl
    ? `https://forkphorus.github.io/embed.html?id=${encodeURIComponent(fileUrl)}&auto-start=true`
    : null

  async function handleShareToggle() {
    if (!project) return
    try {
      const res = await toggleSharePublic(project.id, !project.isPublic)
      setProject({ ...project, isPublic: !project.isPublic, shareToken: res.shareToken })
      show(project.isPublic ? 'Скрыто' : 'Опубликовано', 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  function copyShareLink() {
    if (!project?.shareToken) return
    const url = `${window.location.origin}${import.meta.env.BASE_URL.replace(/\/$/, '')}/scratch/share/${project.shareToken}`
    void navigator.clipboard.writeText(url)
    show('Ссылка скопирована', 'success')
  }

  return (
    <PlatformShell>
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div style={{ maxWidth: 900, margin: '24px auto', padding: '0 16px' }}>
        {!publicMode && (
          <button className="kb-btn" style={{ marginBottom: 16 }} onClick={() => navigate('/scratch')}>
            ← К моим проектам
          </button>
        )}

        {loading ? (
          <div className="kb-card" style={{ padding: 40, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
        ) : !project ? (
          <div className="kb-card" style={{ padding: 40, textAlign: 'center', color: 'var(--ink-soft)' }}>Проект не найден</div>
        ) : (
          <>
            <h1 style={{ fontSize: 24, fontWeight: 900, margin: '0 0 8px' }}>{project.title}</h1>
            {project.description && <p style={{ color: 'var(--ink-soft)', marginTop: 0 }}>{project.description}</p>}

            <div style={{ marginTop: 16, borderRadius: 16, overflow: 'hidden', boxShadow: 'var(--sh-3)' }}>
              {playerUrl && (
                <iframe
                  src={playerUrl}
                  style={{ width: '100%', height: 480, border: 'none', display: 'block' }}
                  title={project.title}
                  allow="autoplay; fullscreen"
                />
              )}
            </div>

            <div style={{ marginTop: 16, padding: 14, background: 'var(--paper-2)', borderRadius: 10, fontSize: 12, color: 'var(--ink-soft)', display: 'flex', gap: 16, flexWrap: 'wrap' }}>
              <span>👁 {project.viewCount} просмотров</span>
              <span>📦 {(project.sizeBytes / 1024).toFixed(0)} KB</span>
              {project.gradedAt && <span>⭐ Оценка: {project.grade}/5</span>}
            </div>

            {!publicMode && (
              <div style={{ marginTop: 16, display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                <button className="kb-btn" onClick={() => navigate(`/scratch/edit/${project.id}`)}>
                  ✏️ Редактировать
                </button>
                <button className="kb-btn" onClick={() => void handleShareToggle()}>
                  {project.isPublic ? '🔒 Сделать приватным' : '🌐 Опубликовать'}
                </button>
                {project.isPublic && project.shareToken && (
                  <button className="kb-btn" onClick={copyShareLink}>
                    🔗 Скопировать ссылку
                  </button>
                )}
              </div>
            )}

            {project.feedback && (
              <div className="kb-card" style={{ marginTop: 16, padding: 16, background: 'var(--violet-soft)' }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--violet-ink)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 6 }}>Отзыв учителя</div>
                <div style={{ fontSize: 14, lineHeight: 1.55 }}>{project.feedback}</div>
              </div>
            )}
          </>
        )}
      </div>
    </PlatformShell>
  )
}
